head.b:skin:
:root {
  --ow-bg: #07111f;
  --ow-panel: rgba(8, 18, 32, 0.9);
  --ow-line: rgba(125, 211, 252, 0.22);
  --ow-text: #f8fbff;
  --ow-muted: #9fb2c7;
  --ow-cyan: #5eead4;
  --ow-yellow: #facc15;
}

* {
  box-sizing: border-box;
}

html,
body {
  min-height: 100%;
  margin: 0;
  overflow: hidden;
  background:
    radial-gradient(circle at 18% 20%, rgba(94, 234, 212, 0.2), transparent 30%),
    radial-gradient(circle at 80% 72%, rgba(250, 204, 21, 0.14), transparent 28%),
    linear-gradient(135deg, #07111f, #0b2030);
  color: var(--ow-text);
  font-family: "Inter", Arial, sans-serif;
}

body {
  width: 100vw;
  height: 100vh;
}

.navbar,
.blogger-clickTrap,
.blogger-system {
  display: none !important;
}

.oxygen-blogger-shell {
  position: fixed;
  inset: 0;
  display: grid;
  grid-template-rows: 1fr;
  isolation: isolate;
  overflow: hidden;
}

.oxygen-blogger-shell::before {
  content: "";
  position: absolute;
  inset: 0;
  z-index: -1;
  background:
    linear-gradient(90deg, rgba(125, 211, 252, 0.08) 1px, transparent 1px),
    linear-gradient(rgba(125, 211, 252, 0.06) 1px, transparent 1px);
  background-size: 72px 72px;
  opacity: 0.6;
}

.oxygen-frame {
  width: 100%;
  height: 100vh;
  display: block;
  border: 0;
  background: var(--ow-bg);
}

.oxygen-fallback {
  position: fixed;
  left: 16px;
  right: 16px;
  bottom: 16px;
  z-index: 4;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 14px;
  padding: 12px 14px;
  color: var(--ow-text);
  background: var(--ow-panel);
  border: 1px solid var(--ow-line);
  border-radius: 8px;
  box-shadow: 0 18px 48px rgba(0, 0, 0, 0.28);
  pointer-events: none;
}

.oxygen-fallback span {
  color: var(--ow-muted);
  font-size: 0.86rem;
  font-weight: 800;
}

.oxygen-fallback a {
  min-height: 40px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 0 14px;
  color: #07111f;
  background: linear-gradient(135deg, var(--ow-cyan), #0ea5e9 58%, var(--ow-yellow));
  border-radius: 8px;
  font-size: 0.86rem;
  font-weight: 950;
  text-decoration: none;
  white-space: nowrap;
  pointer-events: auto;
}

.blogger-hidden-content {
  position: absolute;
  width: 1px;
  height: 1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
}

@media (max-width: 640px) {
  .oxygen-fallback {
    align-items: stretch;
    flex-direction: column;
  }

  .oxygen-fallback a {
    width: 100%;
  }
}
